mapper.select:
SELECT FLIGHT_ID AS flightId, AIRLINE AS airline, DEPARTURE AS departure, ARRIVAL AS arrival, FLIGHT_TYPE AS flightType, DEPART_TIME AS departTime, ARRIVE_TIME AS arriveTime, DURATION AS duration, PRICE AS price, SEAT_CLASS AS seatClass, FLIGHT_DATE AS flightDate FROM TRV_FLIGHT
AND FLIGHT_TYPE = #{flightType}
AND DEPARTURE = #{departure}
AND ARRIVAL LIKE '%' || #{arrival} || '%'
ORDER BY FLIGHT_DATE ASC, DEPART_TIME ASC
